import React, { useState, useRef } from 'react';
import { UserProfile, Region, Gender } from '../types';
import { User, MapPin, Hash, Briefcase, Phone, Save, LogOut, Download, Upload, FileJson, AlertCircle } from 'lucide-react';

interface UserProfileViewProps {
  profile: UserProfile;
  onUpdate: (profile: UserProfile) => void;
  onLogout: () => void;
}

interface InputFieldProps {
  icon: React.ElementType;
  label: string;
  field: keyof UserProfile;
  disabled: boolean;
  type?: string;
  value: string;
  isEditing: boolean;
  onChange: (val: string) => void;
}

const InputField: React.FC<InputFieldProps> = ({ icon: Icon, label, field, disabled, type = "text", value, isEditing, onChange }) => (
  <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
    <label className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">
      <Icon size={12} /> {label}
    </label>
    {isEditing && !disabled ? (
      <input
        type={type}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold text-slate-800 focus:outline-none focus:ring-2 focus:ring-emerald-500"
      />
    ) : (
      <p className="text-base font-bold text-slate-800 px-1 truncate">
        {value || '-'}
      </p>
    )}
  </div>
);

const UserProfileView: React.FC<UserProfileViewProps> = ({ profile, onUpdate, onLogout }) => {
  const [formData, setFormData] = useState<UserProfile>(profile);
  const [isEditing, setIsEditing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const regions: Region[] = ['서울', '경기', '인천', '강원', '충청', '전라', '경상', '제주', '해외'];

  const handleChange = (key: keyof UserProfile, value: string) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const handleSave = () => {
    onUpdate(formData);
    setIsEditing(false);
    alert('정보가 수정되었습니다.');
  };

  // 데이터 내보내기 (백업)
  const handleExportData = () => {
    try {
      const STORAGE_KEY = 'new_life_app_v2_data';
      const rawData = localStorage.getItem(STORAGE_KEY);

      if (!rawData) {
        alert('저장된 데이터가 없습니다.');
        return;
      }

      const blob = new Blob([rawData], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');

      // 파일명 생성 (예: NewLife_Backup_2023-10-25.json)
      const date = new Date().toISOString().split('T')[0];
      link.href = url;
      link.download = `NewLife_Backup_${date}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error('Export failed:', error);
      alert('데이터 내보내기에 실패했습니다.');
    }
  };

  // 데이터 불러오기 (복원)
  const handleImportClick = () => {
    if (window.confirm('데이터를 복원하면 현재 기록된 모든 데이터가 덮어씌워집니다. 계속하시겠습니까?')) {
      fileInputRef.current?.click();
    }
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = e.target?.result as string;
        // 유효성 검사: JSON 파싱 가능 여부 확인
        const parsed = JSON.parse(json);

        if (!parsed.dailyData && !parsed.profile) {
          throw new Error('유효하지 않은 데이터 형식입니다.');
        }

        const STORAGE_KEY = 'new_life_app_v2_data';
        localStorage.setItem(STORAGE_KEY, json);

        alert('데이터가 성공적으로 복원되었습니다. 앱을 다시 시작합니다.');
        window.location.reload();
      } catch (error) {
        console.error('Import failed:', error);
        alert('데이터 복원에 실패했습니다. 올바른 백업 파일인지 확인해주세요.');
      }
    };
    reader.readAsText(file);
    // 같은 파일을 다시 선택할 수 있도록 value 초기화
    event.target.value = '';
  };

  return (
    <div className="pb-20 space-y-6">
      <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white text-center relative overflow-hidden shadow-xl">
        <div className="absolute top-0 left-0 w-full h-full opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
        <div className="relative z-10">
          <div className="w-20 h-20 bg-emerald-500 rounded-full mx-auto mb-4 flex items-center justify-center text-2xl font-bold shadow-lg shadow-emerald-900/50">
            {profile.name[0]}
          </div>
          <h2 className="text-2xl font-bold">{profile.name}</h2>
          <p className="text-emerald-400 text-sm font-medium mt-1">{profile.affiliation || '소속 없음'}</p>
        </div>
      </div>

      <div className="flex items-center justify-between px-2">
        <h3 className="font-bold text-slate-800 text-lg">내 정보</h3>
        {!isEditing ? (
          <button 
            onClick={() => setIsEditing(true)}
            className="text-xs bg-slate-100 text-slate-600 px-4 py-2 rounded-xl font-bold hover:bg-slate-200 transition-colors"
          >
            수정하기
          </button>
        ) : (
          <div className="flex gap-2">
            <button 
              onClick={() => {
                setFormData(profile);
                setIsEditing(false);
              }}
              className="text-xs bg-slate-100 text-slate-500 px-4 py-2 rounded-xl font-bold"
            >
              취소
            </button>
            <button 
              onClick={handleSave}
              className="text-xs bg-emerald-600 text-white px-4 py-2 rounded-xl font-bold shadow-md shadow-emerald-200 flex items-center gap-1"
            >
              <Save size={12} /> 저장
            </button>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <InputField 
          icon={User} 
          label="아이디" 
          field="userId" 
          disabled={true} 
          value={formData.userId}
          isEditing={isEditing}
          onChange={(val) => handleChange('userId', val)}
        />
        <InputField 
          icon={User} 
          label="성명" 
          field="name" 
          disabled={false} 
          value={formData.name}
          isEditing={isEditing}
          onChange={(val) => handleChange('name', val)}
        />
        <InputField 
          icon={Hash} 
          label="나이" 
          field="age" 
          disabled={false} 
          type="number" 
          value={formData.age}
          isEditing={isEditing}
          onChange={(val) => handleChange('age', val)}
        />
        <InputField 
          icon={Briefcase} 
          label="소속" 
          field="affiliation" 
          disabled={false} 
          value={formData.affiliation}
          isEditing={isEditing}
          onChange={(val) => handleChange('affiliation', val)}
        />
        <InputField 
          icon={Phone} 
          label="전화번호" 
          field="phoneNumber" 
          disabled={false} 
          type="tel" 
          value={formData.phoneNumber}
          isEditing={isEditing}
          onChange={(val) => handleChange('phoneNumber', val)}
        />

        {/* 지역 선택은 커스텀 처리 */}
        <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
          <label className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">
            <MapPin size={12} /> 지역
          </label>
          {isEditing ? (
            <select
              value={formData.region}
              onChange={(e) => handleChange('region', e.target.value)}
              className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm font-bold text-slate-800 focus:outline-none focus:ring-2 focus:ring-emerald-500"
            >
              {regions.map((r) => <option key={r} value={r}>{r}</option>)}
            </select>
          ) : (
             <p className="text-base font-bold text-slate-800 px-1">{formData.region}</p>
          )}
        </div>

         {/* 성별 선택 커스텀 처리 */}
         <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
          <label className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">
            <User size={12} /> 성별
          </label>
          {isEditing ? (
            <div className="flex bg-slate-50 rounded-lg p-1">
              {(['male', 'female'] as Gender[]).map((g) => (
                <button
                  key={g}
                  onClick={() => handleChange('gender', g)}
                  className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${
                    formData.gender === g ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-400'
                  }`}
                >
                  {g === 'male' ? '남성' : '여성'}
                </button>
              ))}
            </div>
          ) : (
             <p className="text-base font-bold text-slate-800 px-1">{formData.gender === 'male' ? '남성' : '여성'}</p>
          )}
        </div>
      </div>

      {/* 데이터 백업 관리 섹션 */}
      <div className="pt-6">
        <h3 className="font-bold text-slate-800 text-lg mb-4 px-2">데이터 관리</h3>
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm space-y-4">
          <div className="flex items-start gap-3 p-3 bg-emerald-50 rounded-xl mb-2">
            <AlertCircle className="w-5 h-5 text-emerald-600 flex-shrink-0 mt-0.5" />
            <p className="text-xs text-slate-600 leading-relaxed">
              <strong>PC에 파일로 저장:</strong> 데이터를 잃어버리지 않도록 주기적으로 백업 파일을 다운로드하여 원하는 폴더에 보관하세요.
            </p>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <button 
              onClick={handleExportData}
              className="flex flex-col items-center justify-center gap-2 p-4 bg-slate-50 border border-slate-200 rounded-2xl hover:bg-emerald-50 hover:border-emerald-200 hover:text-emerald-600 transition-all group"
            >
              <div className="p-3 bg-white rounded-xl shadow-sm group-hover:scale-110 transition-transform">
                <Download size={24} className="text-slate-500 group-hover:text-emerald-500" />
              </div>
              <span className="text-sm font-bold">파일로 내보내기</span>
            </button>

            <button 
              onClick={handleImportClick}
              className="flex flex-col items-center justify-center gap-2 p-4 bg-slate-50 border border-slate-200 rounded-2xl hover:bg-blue-50 hover:border-blue-200 hover:text-blue-600 transition-all group"
            >
              <div className="p-3 bg-white rounded-xl shadow-sm group-hover:scale-110 transition-transform">
                <Upload size={24} className="text-slate-500 group-hover:text-blue-500" />
              </div>
              <span className="text-sm font-bold">파일 불러오기</span>
            </button>
            <input 
              type="file" 
              ref={fileInputRef}
              onChange={handleFileChange}
              accept=".json"
              className="hidden" 
            />
          </div>
        </div>
      </div>

      <div className="pt-4">
        <button 
          onClick={onLogout}
          className="w-full py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-red-50 hover:text-red-500 transition-colors"
        >
          <LogOut size={18} /> 로그아웃
        </button>
      </div>
    </div>
  );
};

export default UserProfileView;

import React, { useMemo, useState, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  LineChart, Line, Legend 
} from 'recharts';
// Fixed: Corrected imported function name from getAllData to getAllDailyData
import { getAllDailyData } from '../services/storage';
import { DailyData } from '../types';

type StatsRange = 'week' | 'month' | 'year';

const StatsSection: React.FC = () => {
  const [range, setRange] = useState<StatsRange>('week');
  const [allData, setAllData] = useState<Record<string, DailyData>>({});
  const [isReady, setIsReady] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    try {
      console.log("StatsSection: Fetching data...");
      // Fixed: Updated function call to use getAllDailyData
      const data = getAllDailyData();
      if (data && typeof data === 'object') {
        setAllData(data);
        console.log("StatsSection: Data loaded", Object.keys(data).length, "days found");
      }
      setIsReady(true);
    } catch (e) {
      console.error("StatsSection: Data loading error", e);
      setError("데이터를 불러오는 중 오류가 발생했습니다.");
      setIsReady(true);
    }
  }, []);

  const statsData = useMemo(() => {
    try {
      const sortedDates = Object.keys(allData).sort();
      if (sortedDates.length === 0) return [];

      const today = new Date();
      today.setHours(0, 0, 0, 0);

      const filteredDates = sortedDates.filter(dateStr => {
        const d = new Date(dateStr);
        if (isNaN(d.getTime())) return false;
        d.setHours(0, 0, 0, 0);

        const limitDate = new Date(today);
        if (range === 'week') limitDate.setDate(today.getDate() - 7);
        else if (range === 'month') limitDate.setMonth(today.getMonth() - 1);
        else if (range === 'year') limitDate.setFullYear(today.getFullYear() - 1);

        return d >= limitDate;
      });

      return filteredDates.map(date => {
        const data = allData[date];
        const checklist = data?.checklist || {};
        const completedTasks = Object.values(checklist).filter(val => val === true).length;

        const bibleChapters = (data?.bibleLogs || []).reduce((acc, log) => acc + (Number(log.chapterCount) || 0), 0);
        const readingPages = (data?.readingLogs || []).reduce((acc, log) => acc + (Number(log.pages) || 0), 0);

        return {
          name: date.slice(5),
          '완료된 일과': completedTasks,
          '성경(장)': bibleChapters,
          '독서(쪽)': readingPages,
        };
      });
    } catch (e) {
      console.error("StatsSection: useMemo processing error", e);
      return [];
    }
  }, [allData, range]);

  const cumulativeStats = useMemo(() => {
    const dataArray = Object.values(allData) as DailyData[];
    if (!dataArray.length) return { totalReading: 0, totalBible: 0 };

    const totalReading = dataArray.reduce((acc, d) => 
      acc + (d.readingLogs || []).reduce((p, l) => p + (Number(l.pages) || 0), 0), 0);
    const totalBible = dataArray.reduce((acc, d) => 
      acc + (d.bibleLogs || []).reduce((p, l) => p + (Number(l.chapterCount) || 0), 0), 0);

    return { totalReading, totalBible };
  }, [allData]);

  if (!isReady) {
    return (
      <div className="h-64 flex flex-col items-center justify-center bg-white rounded-[2.5rem] border border-slate-100">
        <div className="w-8 h-8 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-slate-400 text-sm">통계 정보를 분석하고 있습니다...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-8 text-center bg-red-50 rounded-[2.5rem] border border-red-100">
        <p className="text-red-600 font-bold">{error}</p>
        <button onClick={() => window.location.reload()} className="mt-4 text-sm text-red-500 underline">새로고침</button>
      </div>
    );
  }

  return (
    <div className="space-y-6 pb-24">
      {/* 요약 카드 */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-emerald-600 p-6 rounded-[2.5rem] shadow-lg shadow-emerald-100">
          <p className="text-emerald-100 text-[10px] font-bold mb-1 uppercase tracking-widest">누적 독서</p>
          <p className="text-3xl font-black text-white">
            {cumulativeStats.totalReading.toLocaleString()}
            <span className="text-sm font-bold ml-1 opacity-60">P</span>
          </p>
        </div>
        <div className="bg-indigo-600 p-6 rounded-[2.5rem] shadow-lg shadow-indigo-100">
          <p className="text-indigo-100 text-[10px] font-bold mb-1 uppercase tracking-widest">누적 성경</p>
          <p className="text-3xl font-black text-white">
            {cumulativeStats.totalBible.toLocaleString()}
            <span className="text-sm font-bold ml-1 opacity-60">장</span>
          </p>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] p-6 shadow-sm border border-slate-100 min-h-[500px]">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-10">
          <div>
            <h2 className="text-xl font-bold text-slate-800">성장 리포트</h2>
            <p className="text-xs text-slate-400 mt-1">기록의 축적이 삶의 간증이 됩니다.</p>
          </div>
          <div className="flex bg-slate-100 p-1.5 rounded-2xl w-full sm:w-auto">
            {(['week', 'month', 'year'] as StatsRange[]).map((r) => (
              <button
                key={r}
                onClick={() => setRange(r)}
                className={`flex-1 sm:flex-none px-5 py-2 text-xs font-bold rounded-xl transition-all ${
                  range === r 
                    ? 'bg-white text-emerald-600 shadow-sm' 
                    : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                {r === 'week' ? '주간' : r === 'month' ? '월간' : '연간'}
              </button>
            ))}
          </div>
        </div>

        {statsData.length > 0 ? (
          <div className="space-y-12">
            {/* 일과 완료 */}
            <div className="w-full">
              <h3 className="text-sm font-bold text-slate-600 mb-6 flex items-center gap-2">
                <span className="w-1.5 h-4 bg-emerald-500 rounded-full"></span>
                일과 완료 현황
              </h3>
              <div className="h-64 w-full min-h-[250px]">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={statsData} margin={{ top: 10, right: 10, left: -25, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" fontSize={10} tickLine={false} axisLine={false} tick={{ fill: '#94a3b8' }} />
                    <YAxis fontSize={10} tickLine={false} axisLine={false} tick={{ fill: '#94a3b8' }} />
                    <Tooltip 
                      cursor={{ fill: '#f8fafc' }}
                      contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px -5px rgb(0 0 0 / 0.1)', padding: '12px' }}
                    />
                    <Bar dataKey="완료된 일과" fill="#10b981" radius={[6, 6, 0, 0]} barSize={range === 'week' ? 24 : 8} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* 성경/독서 */}
            <div className="w-full border-t border-slate-50 pt-10">
              <h3 className="text-sm font-bold text-slate-600 mb-6 flex items-center gap-2">
                <span className="w-1.5 h-4 bg-indigo-500 rounded-full"></span>
                지성 및 영성 성장
              </h3>
              <div className="h-64 w-full min-h-[250px]">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={statsData} margin={{ top: 10, right: 10, left: -25, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" fontSize={10} tickLine={false} axisLine={false} tick={{ fill: '#94a3b8' }} />
                    <YAxis fontSize={10} tickLine={false} axisLine={false} tick={{ fill: '#94a3b8' }} />
                    <Tooltip 
                      contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px -5px rgb(0 0 0 / 0.1)', padding: '12px' }}
                    />
                    <Legend verticalAlign="top" align="right" iconType="circle" wrapperStyle={{ fontSize: '10px', paddingBottom: '30px' }} />
                    <Line type="monotone" dataKey="성경(장)" stroke="#6366f1" strokeWidth={3} dot={{ r: 4, strokeWidth: 2, fill: '#fff' }} activeDot={{ r: 6 }} />
                    <Line type="monotone" dataKey="독서(쪽)" stroke="#10b981" strokeWidth={3} dot={{ r: 4, strokeWidth: 2, fill: '#fff' }} activeDot={{ r: 6 }} />
                  </LineChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        ) : (
          <div className="h-[400px] flex flex-col items-center justify-center border-2 border-dashed border-slate-100 rounded-[2.5rem] bg-slate-50/50">
            <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center shadow-sm mb-4">
              <BarChart className="text-slate-200 w-8 h-8" />
            </div>
            <p className="text-slate-500 font-bold">통계 데이터가 없습니다.</p>
            <p className="text-slate-400 text-xs mt-2 px-10 text-center leading-relaxed">
              최근 7일 내에 기록된 활동이 없습니다.<br/>
              오늘의 일과를 먼저 체크해볼까요?
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default StatsSection;
